Concrete C++ implementation of Floyd's two-phase algorithm. Returns the cycle-start node, or nullptr if no cycle exists.

struct ListNode { int val; ListNode* next; };

ListNode* detect_cycle_start(ListNode* head) {
    // Phase 1: detect a cycle.
    ListNode* slow = head;
    ListNode* fast = head;
    while (fast != nullptr && fast->next != nullptr) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast) {
            // Phase 2: find the cycle start.
            ListNode* probe = head;
            while (probe != slow) {
                probe = probe->next;
                slow  = slow->next;
            }
            return probe;
        }
    }
    return nullptr;  // no cycle
}
